172	  const tryRecoverNickCollision = (): boolean => {
173	    const nickServEnabled = options.nickserv?.enabled !== false;
174	    const nickservPassword = sanitizeIrcOutboundText(options.nickserv?.password ?? "");
175	    if (nickServEnabled && !nickServRecoverAttempted && nickservPassword) {
176	      nickServRecoverAttempted = true;
177	      try {
178	        const service = sanitizeIrcTarget(options.nickserv?.service?.trim() || "NickServ");
179	        sendRaw(`PRIVMSG ${service} :GHOST ${desiredNick} ${nickservPassword}`);
180	        sendRaw(`NICK ${desiredNick}`);
181	        return true;
182	      } catch (err) {
