254	interface RelayHealthStats {
255	  successCount: number;
256	  failureCount: number;
257	  latencySum: number;
258	  latencyCount: number;
259	  lastSuccess: number;
260	  lastFailure: number;
261	}
262	
263	interface RelayHealthTracker {
264	  /** Record a successful operation */
265	  recordSuccess: (relay: string, latencyMs: number) => void;
266	  /** Record a failed operation */
267	  recordFailure: (relay: string) => void;
268	  /** Get health score (0-1, higher is better) */
269	  getScore: (relay: string) => number;
270	  /** Get relays sorted by health (best first) */
271	  getSortedRelays: (relays: string[]) => string[];
272	}
273	
274	function createRelayHealthTracker(): RelayHealthTracker {
275	  const stats = new Map<string, RelayHealthStats>();
276	
277	  function getOrCreate(relay: string): RelayHealthStats {
278	    let s = stats.get(relay);
279	    if (!s) {
280	      s = {
281	        successCount: 0,
282	        failureCount: 0,
283	        latencySum: 0,
284	        latencyCount: 0,
285	        lastSuccess: 0,
286	        lastFailure: 0,
287	      };
288	      stats.set(relay, s);
289	    }
290	    return s;
291	  }
292	
293	  return {
294	    recordSuccess(relay: string, latencyMs: number): void {
295	      const s = getOrCreate(relay);
296	      s.successCount++;
297	      s.latencySum += latencyMs;
298	      s.latencyCount++;
299	      s.lastSuccess = Date.now();
300	    },
301	
302	    recordFailure(relay: string): void {
303	      const s = getOrCreate(relay);
304	      s.failureCount++;
305	      s.lastFailure = Date.now();
306	    },
307	
308	    getScore(relay: string): number {
309	      const s = stats.get(relay);
310	      if (!s) {
311	        return 0.5;
312	      } // Unknown relay gets neutral score
313	
314	      const total = s.successCount + s.failureCount;
315	      if (total === 0) {
316	        return 0.5;
317	      }
318	
319	      // Success rate (0-1)
320	      const successRate = s.successCount / total;
321	
322	      // Recency bonus (prefer recently successful relays)
323	      const now = Date.now();
324	      const recencyBonus =
325	        s.lastSuccess > s.lastFailure
326	          ? Math.max(0, 1 - (now - s.lastSuccess) / HEALTH_WINDOW_MS) * 0.2
327	          : 0;
328	
329	      // Latency penalty (lower is better)
330	      const avgLatency = s.latencyCount > 0 ? s.latencySum / s.latencyCount : 1000;
331	      const latencyPenalty = Math.min(0.2, avgLatency / 10000);
332	
333	      return Math.max(0, Math.min(1, successRate + recencyBonus - latencyPenalty));
334	    },
335	
336	    getSortedRelays(relays: string[]): string[] {
337	      return [...relays].toSorted((a, b) => this.getScore(b) - this.getScore(a));
338	    },
339	  };
340	}
