import {
  createChatChannelPlugin,
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
} from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// getChatChannelMeta is the standard way to derive channel metadata from the
// bundled plugin registry. pulseboard will need to be registered in
// CHAT_CHANNEL_ORDER (src/channels/ids.ts) before getChatChannelMeta can be
// called with "pulseboard" at runtime. Until then, we type the inline meta
// literal with ReturnType<typeof getChatChannelMeta> to stay aligned with the
// expected shape.
type ChannelMeta = ReturnType<typeof getChatChannelMeta>;

const meta: ChannelMeta = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  blurb: "Connect to PulseBoard bulletin messaging.",
};

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta,
    capabilities: { chatTypes: ["direct", "group"], media: false },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (_cfg) => [DEFAULT_ACCOUNT_ID],
      resolveAccount: (_cfg, _accountId): PulseBoardAccount => ({
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: (_account) => false,
    },
    setup: {
      // Stub: a real implementation would write boardUrl/apiToken/username into
      // channels.pulseboard.accounts[accountId] and return the updated config.
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (_ctx) => {
        // Stub: a real implementation would open a WebSocket/long-poll
        // connection to boardUrl and dispatch inbound messages.
        return { stop: () => {} };
      },
    },
    messaging: {
      normalizeTarget: (raw) => {
        const trimmed = raw.trim();
        return trimmed.length > 0 ? trimmed : undefined;
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => ({
      // Stub: a real implementation would POST to the PulseBoard API.
      channel: "pulseboard",
      messageId: `pulseboard-${Date.now()}`,
      meta: { to },
    }),
  },
});

